final:
module binary_counter(
    input clk,
    input rst,
    output reg [3:0] count,
    output tc
);

always @(posedge clk) begin
    if (rst)
        count <= 4'b0000;
    else
        count <= count + 1;
end

  wire _n01 = count[0] ^ 4'b1111[0];
  wire _n02 = count[1] ^ 4'b1111[1];
  wire _n03 = count[2] ^ 4'b1111[2];
  wire _n04 = count[3] ^ 4'b1111[3];
  assign tc = ~_n01 & ~_n02 & ~_n03 & ~_n04;

endmodule
